JSON.stringify((() => {
  const data = $node["Generate Task ID1"].json;

  const normalizedTaskType =
    data.task_type === "Study" ? "Study" :
    data.task_type === "Work" ? "Work" :
    "Life";

  const normalizedPriority =
    data.priority === "High" ? "High" :
    data.priority === "Medium" ? "Medium" :
    "Low";

  const normalizedEnergy =
    data.energy_required === "High" ? "High" :
    data.energy_required === "Medium" ? "Medium" :
    "Low";

  const normalizedStatus =
    data.status === "Scheduled" ? "Scheduled" :
    data.status === "InProgress" ? "InProgress" :
    data.status === "Done" ? "Done" :
    data.status === "Cancelled" ? "Cancelled" :
    "Inbox";

  const nowTimestamp = Date.now();

  const createdAt =
    (typeof data.created_at === "number" && !Number.isNaN(data.created_at))
      ? data.created_at
      : nowTimestamp;

  const updatedAt =
    (typeof data.updated_at === "number" && !Number.isNaN(data.updated_at))
      ? data.updated_at
      : nowTimestamp;

  function toUnixTimestamp(value, endOfDay = false) {
    if (value === undefined || value === null || String(value).trim() === "") {
      return undefined;
    }

    if (typeof value === "number" && !Number.isNaN(value)) {
      return value;
    }

    const str = String(value).trim();
    const now = new Date();
    const currentYear = now.getFullYear();

    // 匹配 3月30日 / 3月30号
    const mdMatch = str.match(/^(\d{1,2})月(\d{1,2})(日|号)?$/);
    if (mdMatch) {
      const month = Number(mdMatch[1]);
      const day = Number(mdMatch[2]);
      const d = new Date(currentYear, month - 1, day, endOfDay ? 23 : 0, endOfDay ? 59 : 0, 0);
      return d.getTime();
    }

    // 匹配 YYYY-MM-DD
    const ymdMatch = str.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
    if (ymdMatch) {
      const year = Number(ymdMatch[1]);
      const month = Number(ymdMatch[2]);
      const day = Number(ymdMatch[3]);
      const d = new Date(year, month - 1, day, endOfDay ? 23 : 0, endOfDay ? 59 : 0, 0);
      return d.getTime();
    }

    // 匹配 YYYY-MM-DD HH:mm
    const ymdhmMatch = str.match(/^(\d{4})-(\d{1,2})-(\d{1,2})\s+(\d{1,2}):(\d{1,2})$/);
    if (ymdhmMatch) {
      const year = Number(ymdhmMatch[1]);
      const month = Number(ymdhmMatch[2]);
      const day = Number(ymdhmMatch[3]);
      const hour = Number(ymdhmMatch[4]);
      const minute = Number(ymdhmMatch[5]);
      const d = new Date(year, month - 1, day, hour, minute, 0);
      return d.getTime();
    }

    // 兜底：让 JS 试解析
    const parsed = new Date(str);
    if (!Number.isNaN(parsed.getTime())) {
      return parsed.getTime();
    }

    return undefined;
  }

  const deadlineTs = toUnixTimestamp(data.deadline, true);
  const earliestStartTs = toUnixTimestamp(data.earliest_start, false);

  const fields = {
    task_id: data.task_id || "",
    task_name: data.task_name || "",
    estimated_minutes: Number(data.estimated_minutes ?? 60),
    remaining_minutes: Number(data.remaining_minutes ?? data.estimated_minutes ?? 60),

    priority: normalizedPriority,
    task_type: normalizedTaskType,
    splittable: data.splittable === "Yes" || data.splittable === true ? "Yes" : "No",
    energy_required: normalizedEnergy,
    status: normalizedStatus,

    notes: data.notes || "",

    created_at: createdAt,
    updated_at: updatedAt
  };

  if (deadlineTs !== undefined) {
    fields.deadline = deadlineTs;
  }

  if (earliestStartTs !== undefined) {
    fields.earliest_start = earliestStartTs;
  }

  return { fields };
})())
}}
